#!/usr/bin/env node
/**
 * i18n 批量回填脚本
 *
 * 目的:
 *   zh-CN.json 是唯一真相源,其余 9 个 locale 文件缺失大量 key。
 *   本脚本对每个非 zh-CN / 非 en 的 locale 做深度合并:
 *     - locale 已有的 key → 保留原值(可能是人工翻译)
 *     - locale 缺失的 key → 用 zh-CN 的中文值补上(优于显示原始 key 字串)
 *   对 zh-TW,额外做一次简→繁字符映射(针对新补的值)。
 *
 * 用法:
 *   node scripts/i18n-fill.js                    # 回填所有目标 locale
 *   node scripts/i18n-fill.js --locale=ja        # 只回填 ja
 *   node scripts/i18n-fill.js --dry-run          # 只统计,不写盘
 *
 * 注意:
 *   - zh-CN.json 与 en.json 不会被修改(作为源与成品)
 *   - 输出使用 2 空格缩进,保持与现有文件一致
 */

import { readFileSync, writeFileSync } from 'node:fs'
import { join, resolve } from 'node:path'

const ROOT = resolve(import.meta.dirname, '..')
const I18N_DIR = join(ROOT, 'src/i18n')
const SOURCE_LOCALE = 'zh-CN'
const SKIP_LOCALES = new Set(['zh-CN', 'en'])
const TARGET_LOCALES = ['zh-TW', 'ja', 'ko', 'es', 'fr', 'de', 'pt-BR', 'ar', 'ru']

// ---- CLI 参数 ----
const args = process.argv.slice(2)
const flags = new Set(args.filter(a => a.startsWith('--') && !a.includes('=')))
const kvArgs = new Map(
  args
    .filter(a => a.startsWith('--') && a.includes('='))
    .map(a => {
      const [k, ...rest] = a.slice(2).split('=')
      return [k, rest.join('=')]
    })
)
const DRY_RUN = flags.has('--dry-run')
const FILTER_LOCALE = kvArgs.get('locale') || null

