// ---- 工具函数 ----

function loadJson(path) {
  return JSON.parse(readFileSync(path, 'utf-8'));
}

function writeJson(path, obj) {
  const content = JSON.stringify(obj, null, 2) + '\n';
  writeFileSync(path, content, 'utf-8');
}

/**
 * 深度合并:以 source 为模板(填补 target 缺失的 key),
 * 同时返回填补的 key 数量以及新填入的路径集合(供后续 S2T 映射)。
 *
 * @param {object} target   - 已有 locale(可能空 {})
 * @param {object} source   - zh-CN 源
 * @param {Set<string>} filledPaths - 收集新填充的 "a.b.c" 形式路径
 * @param {string} prefix
 * @returns {object} 新对象
 */
function deepMerge(target, source, filledPaths, prefix = '') {
  // source 必然是对象;若非对象直接返回 source(但顶层恒为对象)
  if (source === null || typeof source !== 'object' || Array.isArray(source)) {
    return source;
  }
  const merged = {};
  const isTargetObj = target && typeof target === 'object' && !Array.isArray(target);
  for (const [k, sv] of Object.entries(source)) {
    const path = prefix ? `${prefix}.${k}` : k;
    const tv = isTargetObj ? target[k] : undefined;
    if (sv !== null && typeof sv === 'object' && !Array.isArray(sv)) {
      // 嵌套对象:递归
      const subTarget = (tv !== null && typeof tv === 'object' && !Array.isArray(tv)) ? tv : {};
      merged[k] = deepMerge(subTarget, sv, filledPaths, path);
    } else {
      // 叶子(字符串/数字/布尔/数组/null)
      if (tv === undefined) {
        // 缺失 → 用 source 值填充,记录路径
        merged[k] = sv;
        filledPaths.add(path);
      } else {
        merged[k] = tv;
      }
    }
  }
  // 保留 target 上 source 没有的 key(孤立 key 不动)
  if (isTargetObj) {
    for (const [k, tv] of Object.entries(target)) {
      if (!(k in merged)) {
        merged[k] = tv;
      }
    }
  }
  return merged;
}

/**
 * 将字符串做简→繁字符映射(逐字替换)。
 * 保留非汉字字符(数字、英文、标点、占位符 {name} 等)。
 */
function simplifiedToTraditional(s) {
  if (typeof s !== 'string') return s;
  let out = '';
  for (const ch of s) {
    out += S2T_MAP[ch] !== undefined ? S2T_MAP[ch] : ch;
  }
  return out;
}

/**
 * 仅对 filledPaths 集合内的叶子做简→繁转换(不污染已有人工繁体译文)。
 */
function applyS2TToFilled(obj, filledPaths, prefix = '') {
  if (obj === null || typeof obj !== 'object' || Array.isArray(obj)) return obj;
  for (const [k, v] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${k}` : k;
    if (v !== null && typeof v === 'object' && !Array.isArray(v)) {
      applyS2TToFilled(v, filledPaths, path);
    } else if (typeof v === 'string' && filledPaths.has(path)) {
      obj[k] = simplifiedToTraditional(v);
    }
  }
  return obj;
}

// ---- 主流程 ----

function main() {
  const sourcePath = join(I18N_DIR, `${SOURCE_LOCALE}.json`);
  const source = loadJson(sourcePath);

  let pendingLocales = TARGET_LOCALES;
  if (FILTER_LOCALE) {
    if (!TARGET_LOCALES.includes(FILTER_LOCALE)) {
      console.error(`locale 不在目标列表中: ${FILTER_LOCALE}`);
      console.error(`可选: ${TARGET_LOCALES.join(', ')}`);
      process.exit(2);
    }
    pendingLocales = [FILTER_LOCALE];
  }

  console.log(`源 locale: ${SOURCE_LOCALE} (${sourcePath})`);
  console.log(`目标 locale: ${pendingLocales.join(', ')}`);
  console.log(`模式: ${DRY_RUN ? 'dry-run (不写盘)' : 'write'}`);
  console.log('');

  const report = [];

  for (const loc of pendingLocales) {
    if (SKIP_LOCALES.has(loc)) continue;
    const path = join(I18N_DIR, `${loc}.json`);
    let existing;
    try {
      existing = loadJson(path);
    } catch (err) {
      console.warn(`  ${loc}: 读取失败 (${err.message}),视为空对象`);
      existing = {};
    }

    const filled = new Set();
    const merged = deepMerge(existing, source, filled);

    let s2tApplied = 0;
    if (loc === 'zh-TW' && filled.size > 0) {
      applyS2TToFilled(merged, filled);
      s2tApplied = filled.size;
    }

    if (!DRY_RUN) {
      writeJson(path, merged);
    }

    const tag = loc === 'zh-TW' ? ` (S2T 处理 ${s2tApplied} 个值)` : '';
    console.log(`  ${loc}: 填补 ${filled.size} 个缺失 key${tag}`);
    report.push({ locale: loc, filled: filled.size, s2tApplied });
  }

  console.log('');
  console.log('完成。');
  if (DRY_RUN) {
    console.log('(dry-run 模式,未写盘)');
  }
  return report;
}

main();
